mapper.delete:
UPDATE t_category 
SET USE_YN = 'N'
WHERE CTGRY_SEQ = #{ctgrySeq}

mapper.update:
UPDATE
	t_category
SET
	ORDER_NO = #{orderNo}
WHERE
	CTGRY_SEQ = #{ctgrySeq}

mapper.select:
/**카테고리 1차 ~3차까지 이름 정렬*/
	select a.ctgry_nm ctg3_nm ,b.ctgry_nm ctg2_nm ,c.ctgry_nm ctg1_nm
	,a.*
	from t_category a 
	left join t_category b on a.parent_seq = b.ctgry_seq
	left join t_category c on b.parent_seq = c.ctgry_seq
	where a.ctgry_depth = 3 and a.use_yn = 'Y'
	and b.ctgry_seq is not null
	and c.ctgry_seq is not null
	 and c.ctgry_seq = #{srchCtg1Seq} 
	 and b.ctgry_seq = #{srchCtg2Seq} 
	 and a.ctgry_seq = #{srchCtg3Seq}
